input.command:
curl -s -X POST \
  -H "Authorization: Bearer $GITHUB_TOKEN" \
  -H "Content-Type: application/json" \
  "https://api.github.com/graphql" \
  -d '{
    "query": "query($owner:String!,$name:String!,$number:Int!){repository(owner:$owner,name:$name){pullRequest(number:$number){reviewThreads(first:100){nodes{id isResolved comments(first:10){nodes{databaseId body author{login}}}}}}}}",
    "variables": {"owner": "tiendv89", "name": "rag-service", "number": 5}
  }' | jq '.'

content.content:
{
  "data": {
    "repository": {
      "pullRequest": {
        "reviewThreads": {
          "nodes": [
            {
              "id": "PRRT_kwDOSGpcmM58Idqb",
              "isResolved": true,
              "comments": {
                "nodes": [
                  {
                    "databaseId": 3109326582,
                    "body": "So I think the approach is that we need map the workspace.yaml to the container on startup then. This needs to update the readme.md and dockerfile.",
                    "author": {
                      "login": "tiendv89"
                    }
                  }
                ]
              }
            },
            {
              "id": "PRRT_kwDOSGpcmM58Impl",
              "isResolved": true,
              "comments": {
                "nodes": [
                  {
                    "databaseId": 3109376064,
                    "body": "All symlinks need to be ignored. \n\nA recommended .gitignore to start with is\n\n```.claude/\n.DS_Store\n.idea\n.vscode```",
                    "author": {
                      "login": "tiendv89"
                    }
                  }
                ]
              }
            },
            {
              "id": "PRRT_kwDOSGpcmM58Ir0E",
              "isResolved": false,
              "comments": {
                "nodes": [
                  {
                    "databaseId": 3109404573,
                    "body": "Should untracked all skills inside .claude please.",
                    "author": {
                      "login": "tiendv89"
                    }
                  }
                ]
              }
            }
          ]
        }
      }
    }
  }
}

